import{_ as e,C as s,o as a,c as n,aw as l,b as o,w as t,a as i,E as r,ag as p}from"./chunks/framework.Dq2onT5h.js";const c=JSON.parse('{"title":"ADR 011: Remote Signing Service for Fast and Secure Digital Signatures","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ADR 011: Remote Signing Service for Fast and Secure Digital Signatures | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"adr/adr-011-remote-signer.md","filePath":"adr/adr-011-remote-signer.md","lastUpdated":1753098206000}');const g=e({name:"adr/adr-011-remote-signer.md"},[["render",function(e,c,g,d,y,u){const h=s("Mermaid");return a(),n("div",null,[c[1]||(c[1]=l('<h1 id="adr-011-remote-signing-service-for-fast-and-secure-digital-signatures" tabindex="-1">ADR 011: Remote Signing Service for Fast and Secure Digital Signatures <a class="header-anchor" href="#adr-011-remote-signing-service-for-fast-and-secure-digital-signatures" aria-label="Permalink to &quot;ADR 011: Remote Signing Service for Fast and Secure Digital Signatures&quot;">​</a></h1><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li>2025-03-14: Initial ADR creation including remote and local signing implementations, gRPC client/server flow.</li><li>2025-04-23: Renumbered from ADR-010 to ADR-011 to maintain chronological order.</li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Rollkit with single or multiple signers requires a fast, secure, and flexible digital signing solution. Currently, nodes perform local signing using keys stored on disk, in plain. However, this approach distributes private keys across many nodes, increasing the risk of compromise. By centralizing the signing process behind a remote service—ideally backed by an HSM (Hardware Security Module)—we can both secure our keys and achieve high availability. This remote signing service will also allow clients written in different languages to use a unified API through gRPC.</p><h2 id="alternative-approaches" tabindex="-1">Alternative Approaches <a class="header-anchor" href="#alternative-approaches" aria-label="Permalink to &quot;Alternative Approaches&quot;">​</a></h2><ul><li><p><strong>Local File-Based Signing Only:</strong> While simpler to implement and sufficient for development, this approach requires each node to hold a copy of the private key, increasing the risk of key compromise and reducing overall system security.</p></li><li><p><strong>REST API for Remote Signing:</strong> A RESTful service could be implemented for signing, but it would likely have higher latency and overhead compared to gRPC. Additionally, REST is less efficient for binary data transfers required for cryptographic operations.</p></li><li><p><strong>Direct HSM Integration at Each Node:</strong> Integrating HSMs directly with every node would be secure but expensive and complex to manage at scale.</p></li></ul><p>The chosen approach of a centralized, remote signing service via gRPC offers a balance of security, performance, and ease of multi-language support.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>We will implement a remote signing service that uses gRPC to communicate between the client node and the signing server. The signing server will act as a front for our secure key storage (which could be an HSM or similar secure system) to sign messages on demand. Additionally, a local file-based signing implementation will be provided for development and fallback scenarios. The interface for signing remains consistent across implementations:</p>',10)),(a(),o(p,null,{default:t(()=>[r(h,{id:"mermaid-53",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5BClient%20Node%5D%20--%3E%7C%22gRPC%20Call%3A%20Sign()%2FGetPublic()%22%7C%20B%5BHSM%20%2F%20Remote%20Signing%20Server%5D%0A%20%20%20%20B%20--%3E%7CUses%7C%20C%5B%22Secure%20Key%20Storage%20(HSM)%22%5D%0A%20%20%20%20B%20--%3E%7CReturns%20Signature%2FPublic%20Key%7C%20A%0A"})]),fallback:t(()=>[...c[0]||(c[0]=[i(" Loading... ",-1)])]),_:1})),c[2]||(c[2]=l('<div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Signer</span><span style="color:#B8A6FF;"> interface</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Cryptographically sign the given bytes.</span></span>\n<span class="line"><span style="color:#94EEFF;">    Sign</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">message </span><span style="color:#767676;">[]</span><span style="color:#B8A6FF;">byte</span><span style="color:#767676;">)</span><span style="color:#767676;"> ([]</span><span style="color:#B8A6FF;">byte</span><span style="color:#767676;">,</span><span style="color:#B8A6FF;"> error</span><span style="color:#767676;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">    // Return a public key paired with this private key.</span></span>\n<span class="line"><span style="color:#94EEFF;">    GetPublic</span><span style="color:#767676;">()</span><span style="color:#767676;"> ([]</span><span style="color:#B8A6FF;">byte</span><span style="color:#767676;">,</span><span style="color:#B8A6FF;"> error</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><h2 id="detailed-design" tabindex="-1">Detailed Design <a class="header-anchor" href="#detailed-design" aria-label="Permalink to &quot;Detailed Design&quot;">​</a></h2><h3 id="grpc-api" tabindex="-1">GRPC API <a class="header-anchor" href="#grpc-api" aria-label="Permalink to &quot;GRPC API&quot;">​</a></h3><div class="language-proto"><button title="Copy Code" class="copy"></button><span class="lang">proto</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">syntax</span><span style="color:#767676;"> =</span><span style="color:#BFF3C2;"> &quot;proto3&quot;</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#B8A6FF;">package</span><span style="color:#BFF3C2;"> signer</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#BFF3C2;"> &quot;google/protobuf/empty.proto&quot;</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#A0A0A0;">// The SignRequest holds the bytes we want to sign.</span></span>\n<span class="line"><span style="color:#B8A6FF;">message</span><span style="color:#94EEFF;"> SignRequest</span><span style="color:#DBD7CA;"> {</span></span>\n<span class="line"><span style="color:#B8A6FF;">  bytes</span><span style="color:#DBD7CA;"> message </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#DBD7CA;">}</span></span>\n<span class="line"><span style="color:#A0A0A0;">// The SignResponse returns the signature bytes.</span></span>\n<span class="line"><span style="color:#B8A6FF;">message</span><span style="color:#94EEFF;"> SignResponse</span><span style="color:#DBD7CA;"> {</span></span>\n<span class="line"><span style="color:#B8A6FF;">  bytes</span><span style="color:#DBD7CA;"> signature </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#DBD7CA;">}</span></span>\n<span class="line"><span style="color:#A0A0A0;">// GetPublicRequest requests the public key</span></span>\n<span class="line"><span style="color:#B8A6FF;">message</span><span style="color:#94EEFF;"> GetPublicRequest</span><span style="color:#DBD7CA;"> {}</span></span>\n<span class="line"><span style="color:#A0A0A0;">// The GetPublicResponse returns the public key.</span></span>\n<span class="line"><span style="color:#B8A6FF;">message</span><span style="color:#94EEFF;"> GetPublicResponse</span><span style="color:#DBD7CA;"> {</span></span>\n<span class="line"><span style="color:#B8A6FF;">  bytes</span><span style="color:#DBD7CA;"> public_key </span><span style="color:#767676;">=</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#DBD7CA;">}</span></span>\n<span class="line"><span style="color:#A0A0A0;">// The SignerService defines the RPCs to sign and to retrieve the public key.</span></span>\n<span class="line"><span style="color:#B8A6FF;">service</span><span style="color:#94EEFF;"> SignerService</span><span style="color:#DBD7CA;"> {</span></span>\n<span class="line"><span style="color:#B8A6FF;">  rpc</span><span style="color:#94EEFF;"> Sign</span><span style="color:#DBD7CA;">(</span><span style="color:#94EEFF;">SignRequest</span><span style="color:#DBD7CA;">) </span><span style="color:#B8A6FF;">returns</span><span style="color:#DBD7CA;"> (</span><span style="color:#94EEFF;">SignResponse</span><span style="color:#DBD7CA;">)</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#B8A6FF;">  rpc</span><span style="color:#94EEFF;"> GetPublic</span><span style="color:#DBD7CA;">(</span><span style="color:#94EEFF;">GetPublicRequest</span><span style="color:#DBD7CA;">) </span><span style="color:#B8A6FF;">returns</span><span style="color:#DBD7CA;"> (</span><span style="color:#94EEFF;">GetPublicResponse</span><span style="color:#DBD7CA;">)</span><span style="color:#767676;">;</span></span>\n<span class="line"><span style="color:#DBD7CA;">}</span></span></code></pre></div><p>Signing operations will typically require very high throughput and minimal latency. Nodes frequently request digital signatures, expecting quick responses. Public key retrievals, while less frequent than signatures, still occur regularly for validation purposes.</p><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Proposed</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h2 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h2><p>• Enhanced Security: Private keys remain secure on a centralized, controlled system. • High Availability: Multiple instances of the signing service behind a load balancer can provide failover. • Language Agnosticism: gRPC allows clients in multiple programming languages to use the same service.</p><h2 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h2><p>• Increased Complexity: Additional operational overhead for managing a remote service. • Network Dependency: Nodes depend on network connectivity to access the signing service. • Potential Latency: Although gRPC is optimized, remote calls add a slight delay compared to local signing.</p><h2 id="neutral" tabindex="-1">Neutral <a class="header-anchor" href="#neutral" aria-label="Permalink to &quot;Neutral&quot;">​</a></h2><p>• Fallback Capability: The availability of both local and remote implementations ensures flexibility during development and production.</p>',14))])}]]);export{c as __pageData,g as default};
